405→    private fun updateReaderTagsList(readerTags: List<ReaderTag>) {
406→        readerTagsList.clear()
407→        readerTagsList.addAll(readerTags)
408→    }
409→
410→    fun onTopBarMenuItemClick(item: MenuElementData.Item.Single) {
411→        val selectedReaderTag = readerTagsList[readerTopBarMenuHelper.getReaderTagIndexFromMenuItem(item)]
412→
413→        // Avoid reloading a content stream that is already loaded
414→        if (item.id != _topBarUiState.value?.selectedItem?.id) {
415→            selectedReaderTag?.let { updateSelectedContent(it) }
416→        }
417→        if (selectedReaderTag != null) {
418→            readerTracker.trackDropdownMenuItemTapped(selectedReaderTag)
419→        }
420→    }
