422→    fun onSubFilterItemSelected(item: SubfilterListItem) {
423→        when (item) {
424→            is SubfilterListItem.SiteAll -> clearTopBarFilter()
425→            is SubfilterListItem.Site -> updateTopBarFilter(item.blog.name, ReaderFilterType.BLOG)
426→            is SubfilterListItem.Tag -> updateTopBarFilter(item.tag.tagDisplayName, ReaderFilterType.TAG)
427→            else -> Unit // do nothing
428→        }
429→    }
430→
431→    private fun clearTopBarFilter() {
432→        val filterUiState = _topBarUiState.value?.filterUiState
433→            ?.copy(selectedItem = null)
434→
435→        viewModelScope.launch(mainDispatcher) {
436→            delay(FILTER_UPDATE_DELAY) // small delay to achieve a fluid animation since other UI updates are happening
437→            _topBarUiState.postValue(
438→                _topBarUiState.value
439→                    ?.copy(filterUiState = filterUiState)
440→            )
441→        }
442→    }
443→
444→    private fun updateTopBarFilter(itemName: String, type: ReaderFilterType) {
445→        val filterUiState = _topBarUiState.value?.filterUiState
446→            ?.copy(selectedItem = ReaderFilterSelectedItem(UiStringText(itemName), type))
447→
448→        viewModelScope.launch(mainDispatcher) {
449→            delay(FILTER_UPDATE_DELAY) // small delay to achieve a fluid animation since other UI updates are happening
450→            _topBarUiState.postValue(
451→                _topBarUiState.value
452→                    ?.copy(filterUiState = filterUiState)
453→            )
454→        }
455→    }
456→
457→    fun hideTopBarFilterGroup(readerTab: ReaderTag) {
458→        val selectedReaderTag = _topBarUiState.value?.selectedItem?.let {
459→            readerTagsList[readerTopBarMenuHelper.getReaderTagIndexFromMenuItem(it)]
460→        } ?: return
461→
462→        if (readerTab != selectedReaderTag) return
463→
464→        _topBarUiState.postValue(
465→            topBarUiState.value?.copy(filterUiState = null)
466→        )
467→    }
468→
469→    fun showTopBarFilterGroup(readerTab: ReaderTag, subFilterItems: List<SubfilterListItem>) {
470→        val selectedReaderTag = _topBarUiState.value?.selectedItem?.let {
471→            readerTagsList[readerTopBarMenuHelper.getReaderTagIndexFromMenuItem(it)]
472→        } ?: return
473→
474→        if (readerTab != selectedReaderTag) return
475→
476→        val blogsFilterCount = subFilterItems.filterIsInstance<SubfilterListItem.Site>().size
477→        val tagsFilterCount = subFilterItems.filterIsInstance<SubfilterListItem.Tag>().size
478→
479→        val filterState = _topBarUiState.value?.filterUiState
480→            ?.copy(
481→                blogsFilterCount = blogsFilterCount,
482→                tagsFilterCount = tagsFilterCount,
483→                showBlogsFilter = shouldShowBlogsFilter(selectedReaderTag),
484→                showTagsFilter = shouldShowTagsFilter(selectedReaderTag),
485→            )
486→            ?: TopBarUiState.FilterUiState(
487→                blogsFilterCount = blogsFilterCount,
488→                tagsFilterCount = tagsFilterCount,
489→                showBlogsFilter = shouldShowBlogsFilter(selectedReaderTag),
490→                showTagsFilter = shouldShowTagsFilter(selectedReaderTag),
491→            )
492→
493→        _topBarUiState.postValue(
494→            topBarUiState.value?.copy(filterUiState = filterState)
495→        )
496→    }
497→
498→    private fun shouldShowBlogsFilter(readerTag: ReaderTag): Boolean {
499→        return readerTag.isFilterable
500→    }
501→
502→    private fun shouldShowTagsFilter(readerTag: ReaderTag): Boolean {
503→        return readerTag.isFilterable && readerTag.organization == Organization.NO_ORGANIZATION
504→    }
