 422→    public static ReaderTag getReaderTag() {
 423→        String tagName = getString(DeletablePrefKey.READER_TAG_NAME);
 424→        if (TextUtils.isEmpty(tagName)) {
 425→            return null;
 426→        }
 427→        int tagType = getInt(DeletablePrefKey.READER_TAG_TYPE);
 428→
 429→        boolean wasFollowing = false;
 430→
 431→        // The intention here is to check if the `DeletablePrefKey.READER_TAG_WAS_FOLLOWING` key
 432→        // was present at all in the Shared Prefs.
 433→        // We could have it not set for example in cases where user is upgrading from
 434→        // a previous version of the app. In those cases we do not have enough information as of the saved
 435→        // tag was a Following tag or not, so (as with empty `DeletablePrefKey.READER_TAG_NAME`)
 436→        // let's do not use this piece of information.
 437→        String wasFallowingString = getString(DeletablePrefKey.READER_TAG_WAS_FOLLOWING);
 438→        if (TextUtils.isEmpty(wasFallowingString)) return null;
 439→
 440→        wasFollowing = getBoolean(DeletablePrefKey.READER_TAG_WAS_FOLLOWING, false);
 441→
 442→        return ReaderUtils.getTagFromTagName(tagName, ReaderTagType.fromInt(tagType), wasFollowing);
 443→    }
