 754→    private static boolean getShowGutenbergInfoPopupForTheNewPosts(PrefKey key, String siteURL) {
 755→        if (TextUtils.isEmpty(siteURL)) {
 756→            return false;
 757→        }
 758→
 759→        Set<String> urls;
 760→        try {
 761→            urls = prefs().getStringSet(key.name(), null);
 762→        } catch (ClassCastException exp) {
 763→            // no operation - This should not happen.
 764→            return false;
 765→        }
 766→        // Check if the current site address is available in the set.
 767→        boolean flag = false;
 768→        if (urls != null) {
 769→            if (urls.contains(siteURL)) {
 770→                flag = true;
 771→                // remove the flag from Prefs
 772→                setShowGutenbergInfoPopupForTheNewPosts(key, siteURL, false);
 773→            }
 774→        }
 775→
 776→        return flag;
 777→    }
 778→
 779→    private static void setShowGutenbergInfoPopupForTheNewPosts(PrefKey key, String siteURL, boolean show) {
 780→        if (TextUtils.isEmpty(siteURL)) {
 781→            return;
 782→        }
 783→        Set<String> urls;
 784→        try {
 785→            urls = prefs().getStringSet(key.name(), null);
 786→        } catch (ClassCastException exp) {
 787→            // nope - this should never happens
 788→            return;
 789→        }
 790→
 791→        Set<String> newUrls = new HashSet<>();
 792→        // re-add the old urls here
 793→        if (urls != null) {
 794→            newUrls.addAll(urls);
 795→        }
 796→
 797→        // 1. First remove & 2. add if necessary
 798→        newUrls.remove(siteURL);
 799→        if (show) {
 800→            newUrls.add(siteURL);
 801→        }
 802→
 803→        SharedPreferences.Editor editor = prefs().edit();
 804→        editor.putStringSet(key.name(), newUrls);
 805→        editor.apply();
 806→    }
