355→    private suspend fun updateTopBarUiState() {
356→        withContext(bgDispatcher) {
357→            val menuItems = readerTopBarMenuHelper.createMenu(readerTagsList)
358→
359→            // if menu is exactly the same as before, don't update
360→            if (_topBarUiState.value?.menuItems == menuItems) return@withContext
361→
362→            // if there's already a selected item, use it, otherwise use the first item
363→            val selectedItem = _topBarUiState.value?.selectedItem
364→                ?: menuItems.first { it is MenuElementData.Item.Single } as MenuElementData.Item.Single
365→
366→            // if there's a selected item and filter state, also use the filter state
367→            val filterUiState = _topBarUiState.value?.filterUiState
368→                ?.takeIf { _topBarUiState.value?.selectedItem != null }
369→
370→            _topBarUiState.postValue(
371→                TopBarUiState(
372→                    menuItems = menuItems,
373→                    selectedItem = selectedItem,
374→                    filterUiState = filterUiState,
375→                    onDropdownMenuClick = ::onDropdownMenuClick,
376→                    isSearchActionVisible = isSearchSupported(),
377→                )
378→            )
379→        }
380→    }
