 445→    public static void setReaderTag(ReaderTag tag) {
 446→        if (tag != null && !TextUtils.isEmpty(tag.getTagSlug())) {
 447→            setString(DeletablePrefKey.READER_TAG_NAME, tag.getTagSlug());
 448→            setInt(DeletablePrefKey.READER_TAG_TYPE, tag.tagType.toInt());
 449→            setBoolean(
 450→                    DeletablePrefKey.READER_TAG_WAS_FOLLOWING,
 451→                    tag.isFollowedSites() || tag.isDefaultInMemoryTag()
 452→            );
 453→        } else {
 454→            prefs().edit()
 455→                   .remove(DeletablePrefKey.READER_TAG_NAME.name())
 456→                   .remove(DeletablePrefKey.READER_TAG_TYPE.name())
 457→                   .remove(DeletablePrefKey.READER_TAG_WAS_FOLLOWING.name())
 458→                   .apply();
 459→        }
 460→    }
