 697→    public static int getImageOptimizeQuality() {
 698→        int quality = getInt(DeletablePrefKey.IMAGE_OPTIMIZE_QUALITY, 0);
 699→        int defaultQuality = WPMediaUtils.OPTIMIZE_IMAGE_ENCODER_QUALITY;
 700→
 701→        // It's necessary to check that the quality int exists in the quality array in case of changes
 702→        // See #19644 for an example of when the array's values were changed
 703→        Context context = WordPress.getContext();
 704→        String[] validQualityValues = context.getResources().getStringArray(R.array.site_settings_image_quality_values);
 705→        boolean isQualityValid = Arrays.asList(validQualityValues).contains(String.valueOf(quality));
