 754→    private static boolean getShowGutenbergInfoPopupForTheNewPosts(PrefKey key, String siteURL) {
 755→        if (TextUtils.isEmpty(siteURL)) {
 756→            return false;
 757→        }
 758→
 759→        Set<String> urls;
 760→        try {
 761→            urls = prefs().getStringSet(key.name(), null);
 762→        } catch (ClassCastException exp) {
 763→            // no operation - This should not happen.
 764→            return false;
 765→        }
 766→        // Check if the current site address is available in the set.
 767→        boolean flag = false;
 768→        if (urls != null) {
 769→            if (urls.contains(siteURL)) {
 770→                flag = true;
 771→                // remove the flag from Prefs
 772→                setShowGutenbergInfoPopupForTheNewPosts(key, siteURL, false);
 773→            }
 774→        }
 775→
 776→        return flag;
 777→    }
