 942→    private static ArrayList<Integer> getRecentlyPickedSiteIds(int limit) {
 943→        String idsAsString = getString(DeletablePrefKey.RECENTLY_PICKED_SITE_IDS, "");
 944→        String[] items = idsAsString.split(",");
 945→
 946→        ArrayList<Integer> siteIds = new ArrayList<>();
 947→        for (String item : items) {
 948→            siteIds.add(StringUtils.stringToInt(item));
 949→            if (siteIds.size() == limit) {
 950→                break;
 951→            }
 952→        }
 953→
 954→        return siteIds;
 955→    }
