 957→    /*
 958→     * adds a local site ID to the top of list of recently chosen sites
 959→     */
 960→    public static void addRecentlyPickedSiteId(Integer localId) {
 961→        if (localId == 0) {
 962→            return;
 963→        }
 964→
 965→        ArrayList<Integer> currentIds = getRecentlyPickedSiteIds(MAX_RECENTLY_PICKED_SITES_TO_SAVE);
 966→
 967→        // remove this ID if it already exists in the list
 968→        int index = currentIds.indexOf(localId);
 969→        if (index > -1) {
 970→            currentIds.remove(index);
 971→        }
 972→
 973→        // add this ID to the front of the list
 974→        currentIds.add(0, localId);
 975→
 976→        // remove at max
 977→        if (currentIds.size() > MAX_RECENTLY_PICKED_SITES_TO_SAVE) {
 978→            currentIds.remove(MAX_RECENTLY_PICKED_SITES_TO_SAVE);
 979→        }
 980→
 981→        // store in prefs
 982→        String idsAsString = TextUtils.join(",", currentIds);
 983→        setString(DeletablePrefKey.RECENTLY_PICKED_SITE_IDS, idsAsString);
 984→    }
