 988→
 989→        int index = currentIds.indexOf(localId);
 990→        if (index > -1) {
 991→            currentIds.remove(index);
 992→            String idsAsString = TextUtils.join(",", currentIds);
 993→            setString(DeletablePrefKey.RECENTLY_PICKED_SITE_IDS, idsAsString);
