 83→    private fun ReaderInterestsFragmentLayoutBinding.startObserving(entryPoint: EntryPoint) {
 84→        viewModel.uiState.observe(viewLifecycleOwner) { uiState ->
 85→            when (uiState) {
 86→                is InitialLoadingUiState -> {
 87→                }
 88→                is ContentUiState -> {
 89→                    updateInterests(uiState.interestsUiState)
 90→                }
 91→                is ErrorUiState -> {
 92→                    updateErrorLayout(uiState)
 93→                }
 94→            }
 95→            updateDoneButton(uiState.doneButtonUiState)
 96→            with(uiHelpers) {
 97→                updateVisibility(progressBar, uiState.progressBarVisible)
 98→                updateVisibility(title, uiState.titleVisible)
 99→                updateVisibility(includeErrorLayout.errorLayout, uiState.errorLayoutVisible)
100→            }
101→        }
102→
103→        viewModel.snackbarEvents.observeEvent(viewLifecycleOwner) {
104→            it.showSnackbar(bottomBar)
105→        }
106→
107→        viewModel.closeReaderInterests.observeEvent(viewLifecycleOwner) {
108→            requireActivity().finish()
109→        }
110→
111→        viewModel.start(
112→            LocaleManager.getLanguage(WordPress.getContext()),
113→            parentViewModel,
114→            entryPoint
115→        )
116→    }
