{"file_path":"/project/WordPress/src/main/java/org/wordpress/android/ui/reader/discover/ReaderDiscoverViewModel.kt","old_string":"    private fun observeFollowStatus() {","new_string":"    private fun shouldShowDiscoverOnboarding(userTags: ReaderTagList): Boolean {
        // Keep existing behavior for a truly empty tag list.
        if (userTags.isEmpty()) return true

        // New accounts are auto-subscribed to Blogging Prompts ("dailyprompt"). Treat that as "no tags" until the
        // user completes Discover onboarding.
        val hasNonDefaultTags = userTags.any { !it.tagSlug.equals(BLOGGING_PROMPTS_TAG_SLUG, ignoreCase = true) }
        if (hasNonDefaultTags) return false

        return !appPrefsWrapper.isReaderDiscoverOnboardingCompleted()
    }

